toolArgs.file_text:
@page "/chat"
@rendermode InteractiveServer
@using sv_64d58499ab9b4c4495ede80841bdff41.Services
@using sv_64d58499ab9b4c4495ede80841bdff41.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="HandleChannelSelected" />

    <MessageArea Channel="_activeChannel"
                 Messages="_messages"
                 ThreadSummaries="_threadSummaries"
                 IsLoadingMore="_isLoadingMore"
                 OnOpenThread="HandleOpenThread"
                 OnReact="HandleReaction"
                 OnSendMessage="HandleSendMessage"
                 OnLoadMore="HandleLoadMore"
                 class="@(_threadOpen ? "thread-open" : "")" />

    @if (_threadOpen)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="HandleCloseThread"
                     OnSendReply="HandleSendReply" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await HandleChannelSelected(_channels[0].Id);
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadSummaries = [];
        _hasMoreMessages = true;

        HandleCloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count >= PageSize;

        await ChatService.MarkChannelReadAsync(channelId);
        await RefreshThreadSummaries();

        // Update the unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task HandleLoadMore()
    {
        if (_isLoadingMore || !_hasMoreMessages || _activeChannel is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
        }
        _hasMoreMessages = older.Count >= PageSize;
        _isLoadingMore = false;
    }

    private async Task HandleSendMessage(string content)
    {
        if (_activeChannel is null) return;

        var message = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(message);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var idx = _messages.FindIndex(m => m.Id == args.MessageId);
        if (idx >= 0)
        {
            var msg = _messages[idx];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                reactions.Remove(existing);
                reactions.Add(existing with { Users = [..existing.Users, "You"] });
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            _messages[idx] = msg with { Reactions = reactions };
        }
    }

    private async Task HandleOpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void HandleCloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task HandleSendReply(string content)
    {
        if (_threadRootMessage is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        await RefreshThreadSummaries();
    }

    private async Task RefreshThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var summaries = new List<ThreadSummary>();
        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                summaries.Add(new ThreadSummary(rootId, thread.Count, thread.Max(t => t.SentAt)));
            }
        }
        _threadSummaries = summaries;
    }
}

